def solution(progresses, speeds):

    arr = [100-i for i in progresses]
    diff = [0 for i in speeds]
    for i in range(len(speeds)):
        diff[i] = arr[i]//speeds[i]
        if arr[i]%speeds[i]>0:
            diff[i]+=1

    j = 1
    ans=[]
    cur=0
    cur_a=1
    while j<len(speeds):
        if diff[j]<diff[cur]:
            cur_a+=1
        else:
            ans.append(cur_a)
            cur_a=1
            cur=j
        j+=1
    if cur!=j:
        ans.append(cur_a)
    return ans
