def solution(name):
    if len(name)==1:
        return min(abs(ord(name[0])-ord('A')), abs(ord(name[0])-ord('Z')))
    i=1
    while name[i]=='A':
        i+=1

    cnt = min(len(name)-1, len(name)-i+1)
    for i in range(len(name)):
        cnt+=min(abs(ord(name[i])-ord('A')), abs(ord(name[i])-ord('Z')))
    return cnt

