def solution(name):
    if len(name)==1:
        return min(abs(ord(name[0])-ord('A')), abs(ord(name[0])-ord('Z')+1))
    i=1

    positions = [i for i in range(len(name)) if name[i] != 'A']
    if len(positions)==0:
        return 0

    cur = len(name)-1 

    for i in range(len(positions)-1): 
        cur = min(cur, positions[i] * 2 + (len(name) - positions[i+1]), positions[i] + (len(name) - positions[i+1]) * 2)
    if len(positions)==1:
        cur = min(cur, positions[0], len(name)-positions[0])
    for i in range(len(name)):
        cur+=min(abs(ord(name[i])-ord('A')), abs(ord(name[i])-ord('Z')+1))
    return cur

