def solution(scoville, K):
    import heapq

    heapq.heapify(scoville)   # 리스트를 힙으로 변환 (최소 힙)

    count = 0

    while True:

        if scoville[0] >= K:
            return count       # 정상 종료
        elif len(scoville) <= 1:
            return -1     

        first = heapq.heappop(scoville)  # 가장 작은 값 꺼내기
        second = heapq.heappop(scoville)  # 두 번째로 작은 값 꺼내기
        new_food = first + (second * 2)
        heapq.heappush(scoville, new_food)

        count+=1;
    pass

def solution(citations):
    n = len(citations)

    for h in range(n, -1, -1):  # n부터 0까지 감소
        if len([c for c in citations if c >= h]) >= h:
            return h

