        print("2. 회복하기")
        print("3. 상태 확인")
        print("4. 처치 기록 확인")
        print("5. 도망가기")

        choice = input("선택: ").strip()

        if choice == "1":
            monster_hp -= 15
            print(f"{monster_name}을 공격했습니다!")

            if monster_hp <= 0:
                print(f"{monster_name}을 처치했습니다!")
                killed_monsters.append(monster_name)
                break

            player_hp -= 10
            print(f"{monster_name}이 반격했습니다!")

            if player_hp <= 0:
                print("플레이어가 쓰러졌습니다.")
                break

        elif choice == "2":
            player_hp += 20
            if player_hp > 100:
                player_hp = 100
            print("체력을 회복했습니다.")

        elif choice == "3":
            print(f"플레이어 체력: {player_hp}")
            print(f"{monster_name} 체력: {monster_hp}")

        elif choice == "4":
            if killed_monsters == []:
