def check (scoville, K):
    if min(scoville) >= K:
        return 1
    else: return 0
def mix (scoville):
    heapq.heapify(scoville)
    f = heapq.heappop(scoville)
    s = heapq.heappop(scoville)
    new = f + (s * 2)
    heapq.heappush(scoville, new)
    return scoville

