def solution(name):
    n = len(name)
    answer = sum(min(ord(c) - ord('A'), ord('Z') - ord(c) + 1) for c in name)
    move = n - 1 
    for i in range(n):
        if name[i] == 'A':
            j = i
            while j < n and name[j] == 'A':
                j += 1
            move = min(move, i * 2 + (n - j), i + (n - j) * 2)

    return answer + move

def solution(name):
    n = len(name)
    answer = sum(min(ord(c) - ord('A'), ord('Z') - ord(c) + 1) for c in name)
    move = n - 1 
    for i in range(n):
        if name[i] != 'A':
            j = i
            while j < n and name[j] == 'A':
                j += 1
            move = min(move, i * 2 + (n - j), i + (n - j) * 2)

    return answer + move

