def solution(m, n, puddles):
    # TODO
    dp = [[0] * (n+1) for _ in range(m+1)]
    dp[1][1] = 1
    for x in range(1, m+1):
        for y in range(1, n+1):
             if x == 1 and y == 1:
                continue
             dp[x][y] = dp[x-1][y] + dp[x][y-1]
             if [x, y] in puddles:
                dp[x][y] = 0
    return dp[m][n]

