        s = str.copy()
        p = pos
        c = ord(cur)

        candidates = []
        for i in range(len(str)):
            if s[i] == "_":
                continue
            t = ord(s[i])

            d = min(abs(i-p), len(s)-abs(i-p))
            m = min(abs(c-t), 26-abs(c-t))

            next = s.copy()
            next[i] = "_"
            total = d + m + best(next, i, s[i])
            candidates.append(total)

        if len(candidates) == 0:
            return 0
        return min(candidates)
    return best(name, 0, 'A')

