def solution(name):
    def best(str, pos):
        s = str.copy()
        p = pos
        a = ord('A')

        candidates = []
        for i in range(len(str)):
            if s[i] == "A":
                continue
            t = ord(s[i])

            d = min(abs(i-p), len(s)-abs(i-p))
            m = min(abs(a-t), 26-abs(a-t))

            next = s.copy()
            next[i] = "A"
            total = d + m + best(next, i)
            candidates.append(total)

        if len(candidates) == 0:
            return 0
        return min(candidates)
    return best(name, 0)

