int main() {
    map<string, int> menu;

    while (true) {
        int choice;
        cin >> choice;
        if(choice == 1){
            string name;
            int price;
            cin >> name >> price;
            map<string, int> menu;
            menu[name] = price;
            if (menu.count(name)) {
               cout << "이미 존재하는 메뉴입니다." << endl;
            }
        }
        if(choice == 2){
            string name;
            cin >> name;
             if (menu.count(name)) {
               cout << name << "|" << menu[name] << endl;
            }
            else{
            cout << "메뉴가 없습니다." << endl;
            }
        }
        if(choice == 3){
            string name;
            cin >> name;
             if (menu.count(name)) {
               menu.erase(name);
            }
            else {
                cout << "해당 메뉴가 없습니다." << endl;
            }
        }
        if(choice == 0){
            cout << "종료합니다." << endl;
            break;
        }
    }
    return 0;
}
