int solution(vector<int> scoville, int K) {
    priority_queue<int, vector<int>, greater<int>> pq;
    for (int s : scoville) {
    pq.push(s);
}
    int count=0;
    while (pq.top() < K){
    int first = pq.top();
    pq.pop();            
    int second = pq.top(); 
    pq.pop();              
    int mix = first + (second * 2);
    pq.push(mix);
    count ++;
}
    return count;
}
