#include <algorithm>
int solution(string name) {
    int answer = 0;
    for(int i =0; i<name.length();i++){
        int up = name[i] - 'A';      
        int down = 26 - up;           
        int best = min(up, down);     
        answer += best;
    }

    int move = name.length() - 1;
    for(int i = 0; i < name.length() - 1; i++){
    int next = i + 1;
    while (next < name.length() && name[next] == 'A') {
    next++;
    }
    int st1 = (name.length() - 1);
    int st2 = i * 2 + (name.length() - next);
    int st3 = (name.length() - next) * 2 + i;
    move = min({st1, st2, st3});
    }
    return answer + move;
}

