#include <vector>
#include <queue>
int solution(vector<int> scoville, int K) {
    priority_queue<int, vector<int>, greater<int>> pq;
    int n=scoville.size();

    for(int i=0; i<n; i++){
        pq.push(scoville[i]);
    }
    int n1=pq.top();
    pq.pop();
    int j=0;
    while(n1 < K){
        pq.push(n1+2*pq.top());
        n1=pq.top();
        pq.pop();
        if(pq.empty()){
            return -1;
        }
        j++;
    }
    return j;
}

