def solution(m, n, puddles):
    arr = [[0]*m for _ in range(n)]
    print(arr)

    for puddle in puddles:
        arr[puddle[0]-1][puddle[1]-1] = -1

    for i in range(m-1):
        for j in range(n-1):
            if i == 0 or j == 0:
                arr[i][j] = 1
            else:
                arr[i][j] = arr[i-1][j] + arr[i][j-1]

    return arr[m-1][n-1]

