def solution(m, n, puddles):
    dp = [[0] * (m+1) for _ in range(n+1)]  # 행=세로(n+1), 열=가로(m+1)
    dp[0][0] = 1
    for i in range(n-1):   # i: 세로(y)
        for j in range(m-1):  # j: 가로(x)
            if i == 0 and j == 0:
                continue
            if ([j+1, i+1] not in puddles):  # puddles는 [가로, 세로] = [j, i]
                dp[i][j] = caculate(dp, i, j)
    return dp[n][m] % 1000000007

