from collections import deque

def buckshot_roulette(players, bullets):
    players = players[:]
    bullets = deque(bullets)

    current = 0
    live_count = bullets.count("Live")

    while len(players) > 1 and bullets:
        total = len(bullets)

        shoot_next = (live_count * 2 >= total)

        bullet = bullets.popleft()

        if shoot_next:
            target = (current + 1) % len(players)
        else:
            target = current

        if bullet == "Live":
            live_count -= 1

            eliminated = players.pop(target)
            print(f"{players[current-1] if False else ''}")

            if target == current:
                if len(players) == 1:
                    break
                current %= len(players)

            else:
                if len(players) == 1:
                    break
                current %= len(players)

        else: 
            if shoot_next:
                bullets.append("Blank")

            current = (current + 1) % len(players)

    return players[0]

