                    print(f"\n💰 '{category}' 총 지출: {total}원")

        # 4. 지출 삭제
        elif choice == "4":
            if not expenses:
                print("삭제할 지출 내역이 없습니다.")
            else:
                print("\n--- 전체 지출 내역 ---")
                for i, e in enumerate(expenses, 1):
                    print(f"{i}. [{e['date']}] {e['category']} | {e['amount']}원 | {e['memo']}")

                try:
                    index = int(input("삭제할 항목 번호를 입력하세요: ")) - 1
                    if 0 <= index < len(expenses):
                        removed = expenses.pop(index)
                        print(f"🗑️ 삭제되었습니다: {removed['category']} {removed['amount']}원")
                    else:
                        print("올바른 번호를 입력하세요.")
                except ValueError:
                    print("숫자를 입력하세요.")

        # 5. 종료
        elif choice == "5":
            print("프로그램을 종료합니다. 👋")
            break

        else:
            print("올바른 메뉴 번호를 입력하세요.")

if __name__ == '__main__':
    main()
